using System;
using System.IO;
using Aspose.Pdf;
using Aspose.Pdf.Tagged;
using Aspose.Pdf.LogicalStructure;

class Program
{
    static void Main()
    {
        const string inputPath = "input.pdf";

        if (!File.Exists(inputPath)) { Console.Error.WriteLine($"Not found: {inputPath}"); return; }

        using (Document doc = new Document(inputPath))
        {
            if (!doc.IsTagged) { Console.WriteLine("Not a tagged PDF."); return; }

            ITaggedContent taggedContent = doc.TaggedContent;
            Console.WriteLine($"Title:    {taggedContent.Title}");
            Console.WriteLine($"Language: {taggedContent.Language}");
            Console.WriteLine();

            TraverseStructure(taggedContent.RootElement, 0);
        }
    }

    static void TraverseStructure(StructureElement element, int level)
    {
        string indent = new string(' ', level * 2);
        string text   = element.ActualText ?? string.Empty;
        string alt    = element.AlternativeText ?? string.Empty;  // AlternativeText, NOT .Alt
        Console.WriteLine($"{indent}[{element.GetType().Name}] text='{text}' alt='{alt}'");

        foreach (Element child in element.ChildElements)  // ChildElements — NOT element.Elements
            if (child is StructureElement se)
                TraverseStructure(se, level + 1);
    }
}

