using System;
using System.IO;
using Aspose.Pdf;
using Aspose.Pdf.Annotations;

class Program
{
    static void Main()
    {
        string inputPath  = "input.pdf";
        string outputPath = "output.pdf";

        if (!File.Exists(inputPath)) { Console.Error.WriteLine($"File not found: {inputPath}"); return; }

        using (Document doc = new Document(inputPath))
        {
            Page page = doc.Pages[1];

            // Fully qualify to avoid CS0104 Rectangle ambiguity
            Aspose.Pdf.Rectangle rect = new Aspose.Pdf.Rectangle(100, 500, 300, 550);

            TextAnnotation annotation = new TextAnnotation(page, rect);
            annotation.Title    = "Note Title";
            annotation.Contents = "This is the annotation text.";
            annotation.Open     = true;
            annotation.Icon     = TextIcon.Note;

            page.Annotations.Add(annotation);
            doc.Save(outputPath);
        }

        Console.WriteLine($"Text annotation added and saved to '{outputPath}'.");
    }
}

