using Aspose.Pdf;
using Aspose.Pdf.Tagged;

class Program
{
    static void Main()
    {
        if (!File.Exists("input.pdf")) { Console.Error.WriteLine("input.pdf not found"); return; }

        using (Document doc = new Document("input.pdf"))
        {
            // CORRECT: check for tagged content
            ITaggedContent tagged = doc.TaggedContent;
            bool hasTaggedContent = tagged != null && tagged.RootElement != null;

            // CORRECT: read language and title from DocumentInfo
            string language = doc.Info["Lang"] ?? string.Empty;
            string title    = doc.Info.Title ?? string.Empty;
            Console.WriteLine($"Language: {language}");
            Console.WriteLine($"Title: {title}");

            // CORRECT: write language/title via ITaggedContent setters
            tagged.SetLanguage("en-US");
            tagged.SetTitle("My Document");

            doc.Save("output.pdf");
        }
    }
}

